+  });
+  return { result, setCredential };
+}
+
+function expectMinimaxEnvRefCredentialStored(setCredential: ReturnType<typeof vi.fn>) {
+  expect(setCredential).toHaveBeenCalledWith(
+    { source: "env", provider: "default", id: "MINIMAX_API_KEY" },
+    "ref",
+  );
+}
+
